#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    __global const float *power,
    __global const float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int c_start = __get_global_id(0) * BLOCK_SIZE;
    int r_start = __get_global_id(1) * BLOCK_SIZE;

    int c_end = c_start + BLOCK_SIZE;
    int r_end = r_start + BLOCK_SIZE;

    if (c_end > col) c_end = col;
    if (r_end > row) r_end = row;

    int r, c;
    float delta;

    for (int k = 0; k < num_iterations; k++) {
        const float* src = (k == 0) ? temp : result;

        for (r = r_start; r < r_end; r++) {
            for (c = c_start; c < c_end; c++) {
                int idx = r * col + c;
                bool is_top = (r == 0);
                bool is_bottom = (r == row - 1);
                bool is_left = (c == 0);
                bool is_right = (c == col - 1);

                if (is_top && is_left) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx + 1] - src[idx]) * Rx_1 +
                        (src[idx + col] - src[idx]) * Ry_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else if (is_top && is_right) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx - 1] - src[idx]) * Rx_1 +
                        (src[idx + col] - src[idx]) * Ry_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else if (is_bottom && is_right) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx - 1] - src[idx]) * Rx_1 +
                        (src[idx - col] - src[idx]) * Ry_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else if (is_bottom && is_left) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx + 1] - src[idx]) * Rx_1 +
                        (src[idx - col] - src[idx]) * Ry_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else if (is_top) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx + 1] + src[idx - 1] - 2.0f * src[idx]) * Rx_1 +
                        (src[idx + col] - src[idx]) * Ry_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else if (is_right) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx + col] + src[idx - col] - 2.0f * src[idx]) * Ry_1 +
                        (src[idx - 1] - src[idx]) * Rx_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else if (is_bottom) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx + 1] + src[idx - 1] - 2.0f * src[idx]) * Rx_1 +
                        (src[idx - col] - src[idx]) * Ry_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else if (is_left) {
                    delta = Cap_1 * (power[idx] +
                        (src[idx + col] + src[idx - col] - 2.0f * src[idx]) * Ry_1 +
                        (src[idx + 1] - src[idx]) * Rx_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }
                else {
                    delta = Cap_1 * (power[idx] +
                        (src[idx + col] + src[idx - col] - 2.0f * src[idx]) * Ry_1 +
                        (src[idx + 1] + src[idx - 1] - 2.0f * src[idx]) * Rx_1 +
                        (amb_temp - src[idx]) * Rz_1);
                }

                result[idx] = src[idx] + delta;
            }
        }
    }
}
